// MARK: - secp256k1 (minimal)

struct Secp256k1 {
    static let p = BigInt(0xfffffffffffffffffffffffffffffffffffffffffffffffffffffffefffffc2f)
    static let n = BigInt(0xfffffffffffffffffffffffffffffffebaaedce6af48a03bbfd25e8cd0364141)
    static let Gx = BigInt(0x79be667ef9dcbbac55a06295ce870b07029bfcdb2dce28d959f2815b16f81798)
    static let Gy = BigInt(0x483ada7726a3c4655da4fbfc0e1108a8fd17b448a68554199c47d08ffb10d4b8)

    struct Point {
        var x: BigInt
        var y: BigInt
        var infinity: Bool = false
    }

    static func isOnCurve(_ P: Point) -> Bool {
        if P.infinity { return true }
        // y^2 = x^3 + 7 mod p
        let y2 = BigInt.modMul(P.y, P.y, p)
        let x2 = BigInt.modMul(P.x, P.x, p)
        let x3 = BigInt.modMul(x2, P.x, p)
        let rhs = BigInt.modAdd(x3, BigInt(7), p)
        return y2 == rhs
    }

    static func pointAdd(_ P: Point, _ Q: Point) -> Point {
        if P.infinity { return Q }
        if Q.infinity { return P }
        if P.x == Q.x {
            if BigInt.modAdd(P.y, Q.y, p).isZero { return Point(x: BigInt(0), y: BigInt(0), infinity: true) }
            return pointDouble(P)
        }
        let num = BigInt.modSub(Q.y, P.y, p)
        let den = BigInt.modSub(Q.x, P.x, p)
        let invDen = BigInt.modInvPrime(den, p)
        let lambda = BigInt.modMul(num, invDen, p)
        let xr = BigInt.modSub(BigInt.modSub(BigInt.modMul(lambda, lambda, p), P.x, p), Q.x, p)
        let yr = BigInt.modSub(BigInt.modMul(lambda, BigInt.modSub(P.x, xr, p), p), P.y, p)
        return Point(x: xr, y: yr, infinity: false)
    }

    static func pointDouble(_ P: Point) -> Point {
        if P.infinity { return P }
        if P.y.isZero { return Point(x: BigInt(0), y: BigInt(0), infinity: true) }
        let num = BigInt.modMul(BigInt(3), BigInt.modMul(P.x, P.x, p), p)
        let den = BigInt.modMul(BigInt(2), P.y, p)
        let invDen = BigInt.modInvPrime(den, p)
        let lambda = BigInt.modMul(num, invDen, p)
        let xr = BigInt.modSub(BigInt.modMul(lambda, lambda, p), BigInt.modMul(BigInt(2), P.x, p), p)
        let yr = BigInt.modSub(BigInt.modMul(lambda, BigInt.modSub(P.x, xr, p), p), P.y, p)
        return Point(x: xr, y: yr, infinity: false)
    }

    static func scalarMult(_ k: BigInt, _ P: Point) -> Point {
        var N = P
        var Q = Point(x: BigInt(0), y: BigInt(0), infinity: true)
        var i = 0
        while i < k.bitLength {
            if k.bit(at: i) == 1 { Q = pointAdd(Q, N) }
            N = pointDouble(N)
            i += 1
        }
        return Q
    }

    static func publicKey(fromPrivateKey32 priv: Data, compressed: Bool) throws -> Data {
        guard priv.count == 32 else { throw WalletError.invalidPrivateKey }
        let d = BigInt(priv)
        if d.isZero || d >= n { throw WalletError.invalidPrivateKey }
        let G = Point(x: Gx, y: Gy, infinity: false)
        let Q = scalarMult(d, G)
        precondition(isOnCurve(Q))
        let x = Q.x.toData(paddedTo: 32)
        let y = Q.y.toData(paddedTo: 32)
        if !compressed {
            return Data([0x04]) + x + y
        } else {
            let prefix: UInt8 = (Q.y.toData(paddedTo: 32).last! & 1) == 0 ? 0x02 : 0x03
            return Data([prefix]) + x
        }
    }

    static func deterministicK(priv: Data, msg32: Data) -> BigInt {
        // RFC6979 using HMAC-SHA256, output k in [1,n-1]
        let x = priv
        let h1 = msg32
        var V = Data(repeating: 0x01, count: 32)
        var K = Data(repeating: 0x00, count: 32)

        func hmac(_ key: Data, _ data: Data) -> Data {
            let sk = SymmetricKey(data: key)
            let mac = HMAC<SHA256>.authenticationCode(for: data, using: sk)
            return Data(mac)
        }

        K = hmac(K, V + Data([0x00]) + x + h1)
        V = hmac(K, V)
        K = hmac(K, V + Data([0x01]) + x + h1)
        V = hmac(K, V)

        while true {
            V = hmac(K, V)
            let T = V
            var k = BigInt(T)
            k = k.mod(n)
            if !k.isZero { return k }
            K = hmac(K, V + Data([0x00]))
            V = hmac(K, V)
        }
    }

    static func sign(priv: Data, msg32: Data) throws -> (r: Data, s: Data, v: UInt8) {
        guard priv.count == 32, msg32.count == 32 else { throw WalletError.invalidPrivateKey }
        let d = BigInt(priv)
        if d.isZero || d >= n { throw WalletError.invalidPrivateKey }

        let z = BigInt(msg32)
        let G = Point(x: Gx, y: Gy, infinity: false)

        let k = deterministicK(priv: priv, msg32: msg32)
        let R = scalarMult(k, G)
        let rBI = R.x.mod(n)
        if rBI.isZero { throw WalletError.keyGenerationFailed }
        let kInv = BigInt.modInvPrime(k, n)
        var sBI = BigInt.modMul(kInv, BigInt.modAdd(z, BigInt.modMul(rBI, d, n), n), n)
        if sBI.isZero { throw WalletError.keyGenerationFailed }

        // low-s
        let halfN = n.shiftLeft(0) // copy
        let nMinusS = n - sBI
        if nMinusS < sBI { sBI = nMinusS }

        let r = rBI.toData(paddedTo: 32)
        let s = sBI.toData(paddedTo: 32)

        // recovery id (approx): parity of y and whether x overflowed n
        let yIsOdd = (R.y.toData(paddedTo: 32).last! & 1) == 1
        let xOverflow = R.x >= n
        var rec: UInt8 = 0
        if xOverflow { rec |= 2 }
        if yIsOdd { rec |= 1 }
        let v = rec
        return (r, s, v)
    }
}

// MARK: - Keystore (Keychain)

final class KeychainStore {
    static let shared = KeychainStore()
    private init() {}

    private let service = "com.mvp.cryptowallet.keystore"
    private let account = "default"

    func savePrivateKey(_ key32: Data) throws {
        guard key32.count == 32 else { throw WalletError.invalidPrivateKey }
        try deletePrivateKeyIfExists()

        let access = SecAccessControlCreateWithFlags(nil,
                                                     kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                                                     [.privateKeyUsage, .userPresence],
                                                     nil)

        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: key32,
            kSecAttrAccessControl as String: access as Any
        ]

        query[kSecUseAuthenticationUI as String] = kSecUseAuthenticationUIAllow

        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw WalletError.keyStoreFailed }
    }

    func loadPrivateKey() throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne,
            kSecUseOperationPrompt as String: "Authenticate to access your wallet key"
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        if status == errSecItemNotFound { throw WalletError.keyNotFound }
        guard status == errSecSuccess, let data = item as? Data else { throw WalletError.keyLoadFailed }
        guard data.count == 32 else { throw WalletError.invalidPrivateKey }
        return data
    }

    func deletePrivateKeyIfExists() throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        let status = SecItemDelete(query as CFDictionary)
        if status == errSecSuccess || status == errSecItemNotFound { return }
        throw WalletError.keyDeleteFailed
    }

    func hasKey() -> Bool {
        (try? loadPrivateKey()) != nil
    }
}

// MARK: - Wallet Core (Ethereum-like)

struct EthereumTx: Codable {
    var from: String
    var to: String
    var valueWei: String
    var gasLimit: String
    var maxFeePerGas: String
    var maxPriorityFeePerGas: String
    var nonce: String
    var chainId: String
    var dataHex: String // 0x...
}

final class WalletCore {
    static func generatePrivateKey() throws -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        let status = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        guard status == errSecSuccess else { throw WalletError.keyGenerationFailed }
        let d = Data(bytes)
        let bi = BigInt(d)
        if bi.isZero || bi >= Secp256k1.n { return try generatePrivateKey() }
        return d
    }

    static func ethereumAddress(fromPrivateKey priv: Data) throws -> String {
        let pubUncompressed = try Secp256k1.publicKey(fromPrivateKey32: priv, compressed: false)
        // drop 0x04
        let pub = pubUncompressed.dropFirst()
        let hash = keccak256(pub)
        let addr = hash.suffix(20)
        return "0x" + Hex.string(from: addr)
    }

    static func keccak256(_ data: Data) -> Data {
        Keccak256.hash(data)
    }

    static func personalSign(message: Data, priv: Data) throws -> String {
        // Ethereum personal_sign: keccak256("\x19Ethereum Signed Message:\n" + len + message)
        let prefix = "\u{19}Ethereum Signed Message:\n\(message.count)"
        let payload = Data(prefix.utf8) + message
        let digest = keccak256(payload)
        let sig = try signDigest(digest32: digest, priv: priv)
        return sig
    }

    static func signDigest(digest32: Data, priv: Data) throws -> String {
        guard digest32.count == 32 else { throw WalletError.invalidResponse }
        let (r, s, v0) = try Secp256k1.sign(priv: priv, msg32: digest32)
        let v = Data([UInt8(27 + v0)])
        let sig = r + s + v
        return "0x" + Hex.string(from: sig)
    }

    static func signTransactionHash(txHash32: Data, priv: Data) throws -> String {
        try signDigest(digest32: txHash32, priv: priv)
    }
}

// MARK: - Keccak256 (pure Swift)

enum Keccak256 {
    static func hash(_ data: Data) -> Data {
        var keccak = Keccak(rate: 1088, capacity: 512, outputLength: 32, delimitedSuffix: 0x01)
        keccak.absorb(data)
        return keccak.squeeze()
    }

    struct Keccak {
        let rate: Int
        let capacity: Int
        let outputLength: Int
        let delimitedSuffix: UInt8

        var state: [UInt64] = Array(repeating: 0, count: 25)
        var buffer = Data()
        var finalized = false

        init(rate: Int, capacity: Int, outputLength: Int, delimitedSuffix: UInt8) {
            self.rate = rate
            self.capacity = capacity
            self.outputLength = outputLength
            self.delimitedSuffix = delimitedSuffix
        }

        mutating func absorb(_ data: Data) {
            precondition(!finalized)
            buffer.append(data)
            let rateBytes = rate / 8
            while buffer.count >= rateBytes {
                let block = buffer.prefix(rateBytes)
                buffer.removeFirst(rateBytes)
                xorBlock(block)
                keccakF()
            }
        }

        mutating func squeeze() -> Data {
            if !finalized { finalize() }
            let rateBytes = rate / 8
            var out = Data()
            while out.count < outputLength {
                let block = extractBlock(rateBytes)
                out.append(block.prefix(min(rateBytes, outputLength - out.count)))
                if out.count < outputLength { keccakF() }
            }
            return out
        }

        mutating func finalize() {
            precondition(!finalized)
            let rateBytes = rate / 8
            var pad = Data(buffer)
            pad.append(delimitedSuffix)
            if (delimitedSuffix & 0x80) != 0 && pad.count == rateBytes {
                xorBlock(pad)
                keccakF()
                pad.removeAll(keepingCapacity: true)
            }
            if pad.count < rateBytes {
                pad.append(Data(repeating: 0, count: rateBytes - pad.count))
            }
            pad[rateBytes - 1] ^= 0x80
            xorBlock(pad)
            keccakF()
            buffer.removeAll(keepingCapacity: true)
            finalized = true
        }

        mutating func xorBlock(_ block: Data) {
            let rateWords = rate / 64
            for i in 0..<rateWords {
                let start = i * 8
                let w = block.withUnsafeBytes { ptr -> UInt64 in
                    let b = ptr.bindMemory(to: UInt8.self)
                    var v: UInt64 = 0
                    for j in 0..<8 { v |= UInt64(b[start + j]) << (8 * j) }
                    return v
                }
                state[i] ^= w
            }
        }

        func extractBlock(_ count: Int) -> Data {
            var out = Data(count: count)
            out.withUnsafeMutableBytes { (ptr: UnsafeMutableRawBufferPointer) in
                let b = ptr.bindMemory(to: UInt8.self)
                let rateWords = count / 8
                for i in 0..<rateWords {
                    let w = state[i]
                    let start = i * 8
                    for j in 0..<8 { b[start + j] = UInt8((w >> (8 * j)) & 0xff) }
                }
            }
            return out
        }

        mutating func keccakF() {
            var A = state
            let R: [[Int]] = [
                [0, 36, 3, 41, 18],
                [1, 44, 10, 45, 2],
                [62, 6, 43, 15, 61],
                [28, 55, 25, 21, 56],
                [27, 20, 39, 8, 14]
            ]
            let RC: [UInt64] = [
                0x0000000000000001, 0x0000000000008082, 0x800000000000808A, 0x8000000080008000,
                0x000000000000808B, 0x0000000080000001, 0x8000000080008081, 0x8000000000008009,
                0x000000000000008A, 0x0000000000000088, 0x0000000080008009, 0x000000008000000A,
                0x000000008000808B, 0x800000000000008B, 0x8000000000008089, 0x8000000000008003,
                0x8000000000008002, 0x8000000000000080, 0x000000000000800A, 0x800000008000000A,
                0x8000000080008081, 0x8000000000008080, 0x0000000080000001, 0x8000000080008008
            ]

            func rotl(_ x: UInt64, _ n: Int) -> UInt64 {
                (x << n) | (x >> (64 - n))
            }

            for round in 0..<24 {
                var C = [UInt64](repeating: 0, count: 5)
                for x in 0..<5 {
                    C[x] = A[x] ^ A[x + 5] ^ A[x + 10] ^ A[x + 15] ^ A[x + 20]
                }
                var D = [UInt64](repeating: 0, count: 5)
                for x in 0..<5 {
                    D[x] = C[(x + 4) % 5] ^ rotl(C[(x + 1) % 5], 1)
                }
                for x in 0..<5 {
                    for y in 0..<5 {
                        A[x + 5*y] ^= D[x]
                    }
                }

                var B = [UInt64](repeating: 0, count: 25)
                for x in 0..<5 {
                    for y in 0..<5 {
                        let v = A[x + 5*y]
                        let nx = y
                        let ny = (2*x + 3*y) % 5
                        B[nx + 5*ny] = rotl(v, R[x][y])
                    }
                }

                for x in 0..<5 {
                    for y in 0..<5 {
                        A[x + 5*y] = B[x + 5*y] ^ ((~B[((x + 1) % 5) + 5*y]) & B[((x + 2) % 5) + 5*y])
                    }
                }

                A[0] ^= RC[round]
            }

            state = A
        }
    }
}

// MARK: - Blockchain Communication (JSON-RPC)

final class EthereumRPC {
    let url: URL
    init(rpcURL: URL) { self.url = rpcURL }

    struct RPCRequest: Encodable {
        let jsonrpc: String = "2.0"
        let id: Int
        let method: String
        let params: [EncodableValue]
    }

    struct RPCResponse<T: Decodable>: Decodable {
        let jsonrpc: String?
        let id: Int?
        let result: T?
        let error: RPCError?
    }

    struct RPCError: Decodable {
        let code: Int
        let message: String
    }

    enum EncodableValue: Encodable {
        case string(String)
        case int(Int)
        case array([EncodableValue])
        case object([String: EncodableValue])
        case null

        func encode(to encoder: Encoder) throws {
            var c = encoder.singleValueContainer()
            switch self {
            case .string(let s): try c.encode(s)
            case .int(let i): try c.encode(i)
            case .array(let a): try c.encode(a)
            case .object(let o): try c.encode(o)
            case .null: try c.encodeNil()
            }
        }
    }

    private func call<T: Decodable>(_ method: String, _ params: [EncodableValue], result: T.Type) async throws -> T {
        let req = RPCRequest(id: Int.random(in: 1...1_000_000), method: method, params: params)
        let body = try JSONEncoder().encode(req)
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = body

        do {
            let (data, resp) = try await URLSession.shared.data(for: request)
            guard let http = resp as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
                throw WalletError.invalidResponse
            }
            let decoded = try JSONDecoder().decode(RPCResponse<T>.self, from: data)
            if let e = decoded.error { throw WalletError.server(e.message) }
            guard let r = decoded.result else { throw WalletError.invalidResponse }
            return r
        } catch let e as WalletError {
            throw e
        } catch {
            throw WalletError.network(error)
        }
    }

    func chainId() async throws -> String {
        try await call("eth_chainId", [], result: String.self)
    }

    func getBalance(address: String, block: String = "latest") async throws -> String {
        try await call("eth_getBalance", [.string(address), .string(block)], result: String.self)
    }

    func getTransactionCount(address: String, block: String = "latest") async throws -> String {
        try await call("eth_getTransactionCount", [.string(address), .string(block)], result: String.self)
    }

    func sendRawTransaction(_ rawTxHex: String) async throws -> String {
        try await call("eth_sendRawTransaction", [.string(rawTxHex)], result: String.self)
    }

    func gasPrice() async throws -> String {
        try await call("eth_gasPrice", [], result: String.self)
    }
}

// MARK: - MVP UI

final class WalletViewController: UIViewController {
    private let statusLabel = UILabel()
    private let addressLabel = UILabel()
    private let balanceLabel = UILabel()
    private let rpcField = UITextField()
    private let messageField = UITextField()
    private let signButton = UIButton(type: .system)
    private let genButton = UIButton(type: .system)
    private let deleteButton = UIButton(type: .system)
    private let refreshButton = UIButton(type: .system)
    private let signatureView = UITextView()

    private var rpc: EthereumRPC? {
        guard let u = URL(string: rpcField.text ?? "") else { return nil }
        return EthereumRPC(rpcURL: u)
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Crypto Wallet MVP"
        view.backgroundColor = .systemBackground
        setupUI()
        updateUI()
    }

    private func setupUI() {
        statusLabel.font = .preferredFont(forTextStyle: .headline)
        statusLabel.numberOfLines = 0

        addressLabel.font = .monospacedSystemFont(ofSize: 13, weight: .regular)
        addressLabel.numberOfLines = 0

        balanceLabel.font = .preferredFont(forTextStyle: .subheadline)
        balanceLabel.numberOfLines = 0

        rpcField.placeholder = "RPC URL (e.g. https://mainnet.infura.io/v3/KEY)"
        rpcField.text = "https://cloudflare-eth.com"
        rpcField.borderStyle = .roundedRect
        rpcField.autocapitalizationType = .none
        rpcField.autocorrectionType = .no
        rpcField.keyboardType = .URL

        messageField.placeholder = "Message to sign"
        messageField.text = "Hello from MVP wallet"
        messageField.borderStyle = .roundedRect
        messageField.autocapitalizationType = .none
        messageField.autocorrectionType = .no

        genButton.setTitle("Generate Key", for: .normal)
        genButton.addTarget(self, action: #selector(generateKeyTapped), for: .touchUpInside)

        deleteButton.setTitle("Delete Key", for: .normal)
        deleteButton.addTarget(self, action: #selector(deleteKeyTapped), for: .touchUpInside)

        refreshButton.setTitle("Refresh Balance", for: .normal)
        refreshButton.addTarget(self, action: #selector(refreshTapped), for: .touchUpInside)

        signButton.setTitle("Sign Message", for: .normal)
        signButton.addTarget(self, action: #selector(signTapped), for: .touchUpInside)

        signatureView.font = .monospacedSystemFont(ofSize: 12, weight: .regular)
        signatureView.isEditable = false
        signatureView.layer.borderWidth = 1
        signatureView.layer.borderColor = UIColor.separator.cgColor
        signatureView.layer.cornerRadius = 8
        signatureView.textContainerInset = UIEdgeInsets(top: 10, left: 8, bottom: 10, right: 8)

        let buttonsRow = UIStackView(arrangedSubviews: [genButton, deleteButton])
        buttonsRow.axis = .horizontal
        buttonsRow.spacing = 12
        buttonsRow.distribution = .fillEqually

        let actionsRow = UIStackView(arrangedSubviews: [refreshButton, signButton])
        actionsRow.axis = .horizontal
        actionsRow.spacing = 12
        actionsRow.distribution = .fillEqually

        let stack = UIStackView(arrangedSubviews: [
            statusLabel,
            rpcField,
            addressLabel,
            balanceLabel,
            buttonsRow,
            actionsRow,
            messageField,
            signatureView
        ])
        stack.axis = .vertical
        stack.spacing = 12
        stack.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stack)

        NSLayoutConstraint.activate([
            stack.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -16),
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            signatureView.heightAnchor.constraint(equalToConstant: 180)
        ])
    }

    private func updateUI() {
        let has = KeychainStore.shared.hasKey()
        statusLabel.text = has ? "Wallet ready (key stored in Keychain)" : "No key found. Generate a key to start."
        genButton.isEnabled = !has
        deleteButton.isEnabled = has
        refreshButton.isEnabled = has
        signButton.isEnabled = has
        addressLabel.text = "Address: —"
        balanceLabel.text = "Balance: —"
        signatureView.text = ""
        if has {
            Task { await loadAddressAndBalance() }
        }
    }

    private func setError(_ error: Error) {
        signatureView.text = "Error: \(error.localizedDescription)"
    }

    private func setSignature(_ sig: String) {
        signatureView.text = sig
    }

    private func currentAddress() throws -> String {
        let priv = try KeychainStore.shared.loadPrivateKey()
        return try WalletCore.ethereumAddress(fromPrivateKey: priv)
    }

    private func loadAddressAndBalance() async {
        do {
            let addr = try currentAddress()
            await MainActor.run {
                self.addressLabel.text = "Address: \(addr)"
            }
            guard let rpc = self.rpc else { return }
            let balHex = try await rpc.getBalance(address: addr)
            await MainActor.run {
                self.balanceLabel.text = "Balance (wei, hex): \(balHex)"
            }
        } catch {
            await MainActor.run { self.setError(error) }
        }
    }

    @objc private func generateKeyTapped() {
        Task {
            do {
                let priv = try WalletCore.generatePrivateKey()
                try KeychainStore.shared.savePrivateKey(priv)
                await MainActor.run { self.updateUI() }
            } catch {
                await MainActor.run { self.setError(error) }
            }
        }
    }

    @objc private func deleteKeyTapped() {
        Task {
            do {
                try KeychainStore.shared.deletePrivateKeyIfExists()
                await MainActor.run { self.updateUI() }
            } catch {
                await MainActor.run { self.setError(error) }
            }
        }
    }

    @objc private func refreshTapped() {
        Task { await loadAddressAndBalance() }
    }

    @objc private func signTapped() {
        Task {
            do {
                let priv = try KeychainStore.shared.loadPrivateKey()
                let msg = Data((messageField.text ?? "").utf8)
                let sig = try WalletCore.personalSign(message: msg, priv: priv)
                await MainActor.run { self.setSignature(sig) }
            } catch {
                await MainActor.run { self.setError(error) }
            }
        }
    }
}